export function getOpeningsByDifficulty(level) {
  return OPENINGS.filter(o => o.difficulty === level);
}

function normalizeOpeningSearchValue(value) {
  return `${value ?? ''}`.trim().toLowerCase();
}

function getVariationName(name) {
  const normalizedName = `${name ?? ''}`;
  const separatorIndex = normalizedName.indexOf(':');
  return separatorIndex === -1 ? '' : normalizedName.slice(separatorIndex + 1).trim();
}

export function filterOpenings(query, openings = OPENINGS) {
  const normalizedQuery = normalizeOpeningSearchValue(query);
  if (!normalizedQuery) return openings;

  return openings.filter((opening) => {
    const normalizedName = normalizeOpeningSearchValue(opening.name);
    const normalizedVariation = normalizeOpeningSearchValue(getVariationName(opening.name));
    const normalizedEco = normalizeOpeningSearchValue(opening.eco);
    const normalizedTags = Array.isArray(opening.tags)
      ? opening.tags.map(normalizeOpeningSearchValue)
      : [];

    return (
      normalizedName.includes(normalizedQuery) ||
      normalizedVariation.includes(normalizedQuery) ||
      normalizedEco.includes(normalizedQuery) ||
      normalizedTags.some((tag) => tag.includes(normalizedQuery))
    );
  });
}

export function searchOpenings(query) {
  return filterOpenings(query);
}
